oxy_webhelp_navlinks = {"azr_cloud_acc_setup-d30753e18118":{"topics":[{"title":"Recommendations for adding Azure cloud accounts","shortdesc":"<p class=\"shortdesc\">Rubrik recommends specific actions and best practices for adding Azure cloud accounts         to <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/azr_recommendations_add_cloud_acc.html","attributes":{"data-id":"azr_recommendations_add_cloud_acc"},"menu":{"hasChildren":false},"tocID":"azr_recommendations_add_cloud_acc-d30753e18132","topics":[]},{"title":"Permission categories for Azure workloads","shortdesc":"<p class=\"shortdesc\">For tasks that operate on Azure workloads, <span class=\"ph\">such as indexing,             recovery, and storage tiering, <\/span><span class=\"ph\">RSC<\/span> requires specific permissions.             <span class=\"ph\">RSC<\/span> groups these permissions into categories for granular management so         that you can include or exclude these categories as required.<\/p>","href":"saas\/azr_permission_categories.html","attributes":{"data-id":"azr_permission_categories"},"menu":{"hasChildren":false},"tocID":"azr_permission_categories-d30753e18146","next":"azr_permission_categories-d30753e18146"},{"title":"Evaluate Azure cloud account setup options","shortdesc":"<p class=\"shortdesc\">When adding an Azure cloud account to <span class=\"ph\">RSC<\/span>, it is important to         evaluate the available options for adding the account, including data scanning         capabilities.<\/p>","href":"saas\/azr_evaluate_options_cloud_acc_setup.html","attributes":{"data-id":"azr_evaluate_options_cloud_acc_setup"},"menu":{"hasChildren":false},"tocID":"azr_evaluate_options_cloud_acc_setup-d30753e18192","next":"azr_evaluate_options_cloud_acc_setup-d30753e18192"},{"title":"Azure policy restrictions","shortdesc":"<p class=\"shortdesc\">Azure policies can obstruct <span class=\"ph\">RSC<\/span> operations such as storage account         creation. Knowing how to adjust these policies is crucial for maintaining both security and         compliance.<\/p>","href":"saas\/azure_policy_restrictions.html","attributes":{"data-id":"azure_policy_restrictions"},"menu":{"hasChildren":false},"tocID":"azure_policy_restrictions-d30753e18284","topics":[]},{"title":"Azure ephemeral VMs exclusion from discovery","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> excludes ephemeral Azure virtual machines and managed disks         created by supported third-party services from discovery, based on vendor-specific resource         tags that the third-party services automatically apply. This keeps protection focused on         your own long-lived workloads, prevents wasted protection effort on short-lived resources         that will soon be deleted, and reduces unnecessary discovery load on <span class=\"ph\">RSC<\/span>.<\/p>","href":"saas\/azr_ephemeral_vm_exclusion_from_discovery.html","attributes":{"data-id":"azr_ephemeral_vm_exclusion_from_discovery"},"menu":{"hasChildren":false},"tocID":"azr_ephemeral_vm_exclusion_from_discovery-d30753e18298","topics":[]},{"title":"Configure Azure cloud accounts","shortdesc":"<p class=\"shortdesc\">Start the configuration of your Azure cloud accounts by adding them to <span class=\"ph\">RSC<\/span> and performing other maintenance operations, such as editing and         upgrading accounts.<\/p>","href":"saas\/azr_configuration_cloud_acc.html","attributes":{"data-id":"azr_configuration_cloud_acc"},"menu":{"hasChildren":false},"tocID":"azr_configuration_cloud_acc-d30753e18314","next":"azr_configuration_cloud_acc-d30753e18314"},{"title":"Manage Azure cloud accounts","href":"saas\/azr_entra_domain_mapping_moving_subs.html","menu":{"hasChildren":false},"tocID":"tocId-d30753e18558","next":"tocId-d30753e18558"}]}};